            areas_title_8: "EXPORTACIÓN E IMPORTACIÓN",
            areas_title_9: "CAPTACIÓN DE RECURSOS FINANCIEROS",
            areas_title_10: "RECURSOS HUMANOS",
            areas_title_11: "ANTICIPO DE CUENTAS POR COBRAR",
